import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Realtime from './pages/Realtime';

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const checkAuth = async () => {
            // 1. Kiểm tra xem có token trong localStorage chưa
            const token = localStorage.getItem('access_token');
            if (token) {
                setIsAuthenticated(true);
                setIsLoading(false);
                return;
            }

            // 2. Nếu chưa có token, kiểm tra xem trên URL có trả về 'code' không
            const searchParams = new URLSearchParams(window.location.search);
            const code = searchParams.get('code');

            if (code) {
                try {
                    // Dùng URLSearchParams để định dạng body dạng x-www-form-urlencoded theo chuẩn OAuth2
                    const tokenEndpoint = `${process.env.REACT_APP_COGNITO_DOMAIN}/oauth2/token`;
                    const bodyParams = new URLSearchParams();
                    bodyParams.append('grant_type', 'authorization_code');
                    bodyParams.append('client_id', process.env.REACT_APP_CLIENT_ID);
                    bodyParams.append('code', code);
                    bodyParams.append('redirect_uri', process.env.REACT_APP_REDIRECT_URI);

                    const response = await fetch(tokenEndpoint, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/x-www-form-urlencoded'
                        },
                        body: bodyParams
                    });

                    if (response.ok) {
                        const data = await response.json();
                        // Lưu token vào máy
                        localStorage.setItem('access_token', data.access_token);
                        if (data.id_token) localStorage.setItem('id_token', data.id_token);
                        
                        // Dọn dẹp code trên thanh URL 
                        window.history.replaceState(null, null, window.location.pathname);
                        setIsAuthenticated(true);
                    } else {
                        // Nếu đổi code thất bại (code hết hạn, code giả...), ép đăng nhập lại
                        window.history.replaceState(null, null, window.location.pathname);
                        redirectToLogin();
                    }
                } catch (error) {
                    console.error("Lỗi mạng khi gọi token endpoint:", error);
                    redirectToLogin();
                }
            } else {
                // 3. Không có token, không có code -> Cognito Hosted UI
                redirectToLogin();
            }
            setIsLoading(false);
        };

        checkAuth();
    }, []);

    const redirectToLogin = () => {
        // response_type=code
        const cognitoUrl = `${process.env.REACT_APP_COGNITO_DOMAIN}/login?client_id=${process.env.REACT_APP_CLIENT_ID}&response_type=code&scope=email+openid+phone&redirect_uri=${process.env.REACT_APP_REDIRECT_URI}`;
        window.location.href = cognitoUrl;
    };

    if (isLoading) return <div style={{padding: '50px', textAlign: 'center'}}>Đang xác thực hệ thống...</div>;

    return (
        <Router>
            <Layout>
                <Routes>
                    <Route path="/" element={<Navigate to="/realtime" />} />
                    <Route path="/realtime" element={<Realtime />} />
                    <Route path="/search" element={<div style={{padding: 20}}>Màn hình Tra cứu (Đang xây dựng)</div>} />
                    <Route path="/devices" element={<div style={{padding: 20}}>Màn hình Quản lý thiết bị (Đang xây dựng)</div>} />
                </Routes>
            </Layout>
        </Router>
    );
};

export default App;
